[CmdletBinding()]
param([string]$Root=(Get-Location).Path,[switch]$Json)
$ErrorActionPreference='Stop';$roots=@(Get-ChildItem -LiteralPath $Root -Recurse -Force -Directory -ErrorAction SilentlyContinue|Where-Object{$_.Name -eq '.git'}|ForEach-Object{$_.Parent.FullName});if(Test-Path (Join-Path $Root '.git')){$roots+= $Root};$roots=@($roots|Sort-Object -Unique);$packages=@(Get-ChildItem -LiteralPath $Root -Recurse -Filter package.json -File -ErrorAction SilentlyContinue|ForEach-Object{[pscustomobject]@{path=$_.DirectoryName;manifest='package.json'}});$result=[ordered]@{schemaVersion=1;root=$Root;repositories=$roots;packageBoundaries=$packages;mode=if($roots.Count -gt 1){'multi-repo'}elseif($packages.Count -gt 1){'multi-package'}else{'single-root'};mutation=$false};if($Json){$result|ConvertTo-Json -Depth 4}else{$result|Format-List}
